const html = $input.first().json.data;
const BASE_URL = 'https://www.harry-gerlach.de/';

function decode(str) {
  return str
    .replace(/&szlig;/g, 'ß').replace(/&uuml;/g, 'ü').replace(/&ouml;/g, 'ö')
    .replace(/&auml;/g, 'ä').replace(/&Uuml;/g, 'Ü').replace(/&Ouml;/g, 'Ö')
    .replace(/&Auml;/g, 'Ä').replace(/&amp;/g, '&').replace(/&sup2;/g, '²')
    .replace(/&nbsp;/g, ' ').trim();
}

const staticData = $getWorkflowStaticData('global');
const seen = new Set(staticData.seenHarryGerlachIds ?? []);

const parts = html.split('class="card card--object"');
const newListings = [];

for (const card of parts.slice(1)) {
  const exposeMatch = card.match(/Expos[^<]*<\/dt>\s*<dd[^>]*>([^<]+)<\/dd>/);
  if (!exposeMatch) continue;
  const id = exposeMatch[1].trim();
  if (seen.has(id)) continue;

  const titleMatch = card.match(/itemprop="name">([^<]+)<\/h2>/);
  const title = titleMatch ? decode(titleMatch[1]) : '';

  const addressMatch = card.match(/card--short-info[^>]*>\s*<p>([^<]+)<\/p>/);
  const address = addressMatch ? decode(addressMatch[1]) : '';

  const roomsMatch = card.match(/class="data__title rooms"[^>]*>[^<]*<\/dt>\s*<dd[^>]*>(\d+)/);
  const rooms = roomsMatch ? roomsMatch[1] : '?';

  const sizeMatch = card.match(/class="data__title larea"[^>]*>[^<]*<\/dt>\s*<dd[^>]*>(\d+)/);
  const size = sizeMatch ? sizeMatch[1] : '?';

  const urlMatch = card.match(/class="media"[^>]*href="([^"]+)"/);
  const url = urlMatch ? BASE_URL + urlMatch[1] : BASE_URL + 'wohnung-mieten-berlin/';

  newListings.push({ id, title, address, rooms, size, url });
}

staticData.seenHarryGerlachIds = [...seen, ...newListings.map(l => l.id)].slice(-500);

if (newListings.length === 0) return [];

return newListings.map(({ id, title, address, rooms, size, url }) => ({
  json: { id, title, address, rooms, size, price: 'k.A.', url }
}));

const html = $input.first().json.data;

const staticData = $getWorkflowStaticData('global');
const seen = new Set(staticData.seenBerlinHausIds ?? []);

const jsonLdMatch = html.match(/<script type="application[/]ld[+]json">([\s\S]*?)<[/]script>/);
if (!jsonLdMatch) return [];

const jsonLd = JSON.parse(jsonLdMatch[1]);
const items = jsonLd.itemListElement ?? [];

const itemsByUrl = {};
for (const item of items) {
  itemsByUrl[item.url] = item.name;
}

const newListings = [];
for (const article of html.split('<article ').slice(1)) {
  const urlMatch = article.match(/href="([^"]+)" aria-label=/);
  if (!urlMatch) continue;
  const url = urlMatch[1];
  if (!itemsByUrl[url]) continue;

  const id = url;
  if (seen.has(id)) continue;

  const title = itemsByUrl[url];

  const priceMatch = article.match(/frymo-listing-price-value">(\d[\d,.]+)/);
  const price = priceMatch ? priceMatch[1] : 'k.A.';

  const roomsMatch = article.match(/frymo-listing-rooms[\s\S]*?meta-item-value">(\d+)/);
  const rooms = roomsMatch ? roomsMatch[1] : '?';

  const areaMatch = article.match(/frymo-listing-area[\s\S]*?meta-item-value">(\d[\d,.]+)/);
  const size = areaMatch ? areaMatch[1].replace(',', '.') : '?';

  const locationMatch = article.match(/frymo-listing-location[^>]*><[^>]+>([^<]+)<[/]div>/);
  const address = locationMatch ? locationMatch[1].trim() : '';

  newListings.push({ id, title, url, price, rooms, size, address });
}

staticData.seenBerlinHausIds = [...seen, ...newListings.map(l => l.id)].slice(-500);

if (newListings.length === 0) return [];

return newListings.map(({ id, title, url, price, rooms, size, address }) => ({
  json: { id, title, url, price, rooms, size, address }
}));

const data = $input.first().json;
const listings = data.results ?? [];

const staticData = $getWorkflowStaticData('global');
const seen = new Set(staticData.seenIds ?? []);

const newListings = listings
  .filter(item => !seen.has(String(item.wrk_id)))
  .map(item => ({ id: String(item.wrk_id), item }));

staticData.seenIds = [...seen, ...newListings.map(l => l.id)].slice(-500);

if (newListings.length === 0) return [];

return newListings.map(({ id, item }) => ({
  json: {
    id,
    title: item.titel,
    price: item.preis.toFixed(2),
    size: item.groesse,
    rooms: item.anzahl_zimmer,
    address: `${item.strasse}, ${item.plz} ${item.ort}`,
    url: `https://www.deutsche-wohnen.com/mieten/mietangebote/${item.slug}`,
  }
}));
